def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        base_score = 0
        if ratio < 0.2:
            base_score = ((1 - ratio)**4 + np.sin(ratio * 2 * np.pi)) * 2
        elif 0.2 <= ratio < 0.5:
            base_score = np.log1p(ratio * 4) * 2.5 - np.sqrt(ratio) * 1.5
        elif 0.5 <= ratio < 0.8:
            base_score = 1 / (1 + np.exp(-20 * (ratio - 0.65))) + np.cos(ratio * 6)
        elif 0.8 <= ratio < 0.95:
            base_score = np.tanh(15 * (ratio - 0.85)) + 0.75
        else:
            base_score = 1.5 * np.tanh(20 * (ratio - 0.95)) + 0.2
        penalty = 0
        for j in range(1, 7):
            mod_val = ((item * j**2) % capacity)
            frac = mod_val / (capacity * (j + 1))
            if frac < 0.05:
                penalty += frac * 3
            elif 0.05 <= frac < 0.25:
                penalty += frac * 1.5
            elif 0.25 <= frac < 0.5:
                penalty += frac
            else:
                penalty += frac / (j**2 + 1)
        extra_penalty = 0
        for k in range(1, 5):
            if ratio > 0.4 * k:
                extra_penalty += np.exp(-k**2 * ratio) * (k + 1)
            else:
                extra_penalty += np.log1p(k**2 * ratio + 2) / (k + 2)
        dynamic_factor = 0
        for m in range(1, 4):
            if capacity % (m + 1) == 0:
                dynamic_factor += (m + 1) * ratio**m
            else:
                dynamic_factor += np.sin((m + 1) * ratio * np.pi) * 0.5
        if capacity % 3 == 0:
            final_score = base_score + penalty + extra_penalty + dynamic_factor * 0.7
        elif capacity % 5 == 0:
            final_score = base_score * 1.2 + penalty * 0.8 + extra_penalty + dynamic_factor
        else:
            final_score = base_score + penalty * 1.3 + extra_penalty * 0.9 + dynamic_factor * 0.5
        if final_score < 0:
            final_score = 0
        if final_score > 10:
            final_score = 10
        priorities[i] = final_score
    return priorities
